import java.io.*;

public class CommandInjectionSecure {

    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a command to run: ");
            String command = reader.readLine();

            // Sanitize and validate the user input to prevent Command Injection
            if (!command.matches("[a-zA-Z0-9_]+")) {
                throw new IllegalArgumentException("Invalid command input");
            }

            Process process = Runtime.getRuntime().exec("ls " + command);

            BufferedReader inputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;

            while ((line = inputReader.readLine()) != null) {
                System.out.println(line);
            }

        } catch (IOException e) {
            e.printStackTrace();
        } catch (IllegalArgumentException e) {
            System.err.println("Error: " + e.getMessage());
        }
    }
}

